import React, { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { DatabaseZap, User, Lock, ArrowLeft, Eye, EyeOff } from 'lucide-react'
import { useAuth } from '../context/AuthContext'
import { gsService } from '../lib/googleSheetsService'

const ProfileSelection = () => {
    const { login } = useAuth()
    const [users, setUsers] = useState([])
    const [loading, setLoading] = useState(true)
    
    // Estados para logueo con contraseña
    const [selectedUser, setSelectedUser] = useState(null)
    const [password, setPassword] = useState('')
    const [showPassword, setShowPassword] = useState(false)
    const [error, setError] = useState('')

    useEffect(() => {
        const loadUsers = async () => {
            try {
                await gsService.initialize()
                const dbUsers = gsService.getTable('Usuarios') || []
                if (dbUsers.length > 0) {
                    setUsers(dbUsers.map((u, index) => ({
                        id: String(u.id || u.nombre || index),
                        nombre_vendedor: String(u.nombre || '').toUpperCase(),
                        rol: String(u.rol || 'vendedor').toLowerCase() === 'administrador' ? 'admin' : 'vendedor',
                        clave: String(u.clave !== undefined ? u.clave : '123456').trim()
                    })))
                }
            } catch (err) {
                console.error('Error loading users:', err)
            } finally {
                setLoading(false)
            }
        }
        loadUsers()
    }, [])

    const handleSelectUser = (usr) => {
        setSelectedUser(usr)
        setPassword('')
        setError('')
        setShowPassword(false)
    }

    const handleLoginSubmit = (e) => {
        e.preventDefault()
        if (!selectedUser) return

        const inputPassword = password.trim()
        const userPassword = selectedUser.clave

        if (inputPassword === userPassword) {
            login({
                id: selectedUser.id,
                nombre_vendedor: selectedUser.nombre_vendedor,
                rol: selectedUser.rol
            })
        } else {
            setError('CONTRASEÑA INCORRECTA')
        }
    }

    const handleBack = () => {
        setSelectedUser(null)
        setPassword('')
        setError('')
    }

    return (
        <div className="s-login-container" style={{
            height: '100vh', width: '100vw', display: 'flex', alignItems: 'center', justifyContent: 'center',
            background: 'radial-gradient(circle at center, rgba(0, 230, 118, 0.05) 0%, #000 100%)', position: 'fixed', top: 0, left: 0, zIndex: 100000,
            overflowY: 'auto'
        }}>
            <div style={{ textAlign: 'center', width: '100%', maxWidth: '400px', padding: '2rem' }}>
                
                {/* Cabecera / Logo */}
                <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} style={{ marginBottom: '2.5rem' }}>
                    <h1 style={{ fontSize: '2.5rem', fontWeight: 1000, color: '#fff', letterSpacing: '0.1em' }}>
                        GLOBAL POS <span style={{ color: 'var(--s-neon)' }}>DM</span>
                    </h1>
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', marginTop: '1rem' }}>
                        <DatabaseZap size={20} style={{ color: 'var(--s-neon)' }} />
                        <p style={{ color: 'var(--s-neon)', fontWeight: 700, fontSize: '0.9rem' }}>GOOGLE SHEETS CONECTADO</p>
                    </div>
                </motion.div>

                <AnimatePresence mode="wait">
                    {loading ? (
                        <motion.div 
                            key="loading"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            style={{ color: 'var(--s-neon)', fontWeight: 700, letterSpacing: '0.15em' }}
                        >
                            CARGANDO VENDEDORES...
                        </motion.div>
                    ) : !selectedUser ? (
                        /* VISTA 1: SELECCIONAR USUARIO */
                        <motion.div
                            key="user-select"
                            initial={{ opacity: 0, x: -30 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 30 }}
                            style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}
                        >
                            <p style={{ color: 'var(--s-text-dim)', fontWeight: 800, letterSpacing: '0.1em', marginBottom: '0.5rem' }}>
                                SELECCIONE SU PERFIL PARA INGRESAR
                              </p>
                              
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxHeight: '350px', overflowY: 'auto', paddingRight: '0.5rem' }} className="s-scroll">
                                {users.length > 0 ? (
                                    users.map((usr) => (
                                        <motion.button
                                            key={usr.id}
                                            whileHover={{ scale: 1.02 }}
                                            whileTap={{ scale: 0.98 }}
                                            onClick={() => handleSelectUser(usr)}
                                            className="s-btn s-btn-secondary"
                                            style={{
                                                width: '100%', 
                                                height: '4.5rem', 
                                                fontSize: '1rem', 
                                                letterSpacing: '0.1em',
                                                display: 'flex', 
                                                alignItems: 'center', 
                                                justifyContent: 'flex-start', 
                                                gap: '1.25rem',
                                                padding: '0 1.5rem',
                                                background: 'rgba(255, 255, 255, 0.02)',
                                                border: '1px solid var(--s-glass-border)',
                                                borderRadius: '12px'
                                            }}
                                        >
                                            <div style={{
                                                width: '2.5rem',
                                                height: '2.5rem',
                                                borderRadius: '50%',
                                                background: 'rgba(0, 230, 118, 0.1)',
                                                display: 'flex',
                                                alignItems: 'center',
                                                justifyContent: 'center',
                                                color: 'var(--s-neon)'
                                            }}>
                                                <User size={18} />
                                            </div>
                                            <div style={{ textAlign: 'left' }}>
                                                <div style={{ fontWeight: 800, color: '#fff' }}>{usr.nombre_vendedor}</div>
                                                <div style={{ fontSize: '0.65rem', color: 'var(--s-neon)', fontWeight: 700, textTransform: 'uppercase', marginTop: '0.1rem' }}>
                                                    {usr.rol === 'admin' ? 'Gerente' : 'Vendedor'}
                                                </div>
                                            </div>
                                        </motion.button>
                                    ))
                                ) : (
                                    /* Fallback Administrador Invitado */
                                    <motion.button
                                        whileHover={{ scale: 1.02 }}
                                        whileTap={{ scale: 0.98 }}
                                        onClick={() => handleSelectUser({ id: 'guest', nombre_vendedor: 'ADMINISTRADOR', rol: 'admin', clave: '123456' })}
                                        className="s-btn s-btn-primary"
                                        style={{
                                            width: '100%', height: '5rem', fontSize: '1.2rem', letterSpacing: '0.15em',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '1rem'
                                        }}
                                    >
                                        ENTRAR AL SISTEMA (ADMIN)
                                    </motion.button>
                                )}
                            </div>
                        </motion.div>
                    ) : (
                        /* VISTA 2: INGRESAR CLAVE */
                        <motion.form
                            key="password-entry"
                            initial={{ opacity: 0, x: 30 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: -30 }}
                            onSubmit={handleLoginSubmit}
                            style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem', padding: '1rem 0' }}
                        >
                            {/* Perfil Seleccionado */}
                            <div style={{ 
                                display: 'flex', 
                                alignItems: 'center', 
                                gap: '1rem', 
                                padding: '1rem', 
                                background: 'rgba(0, 230, 118, 0.04)', 
                                border: '1px solid rgba(0, 230, 118, 0.2)',
                                borderRadius: '12px',
                                textAlign: 'left'
                            }}>
                                <div style={{
                                    width: '2.5rem',
                                    height: '2.5rem',
                                    borderRadius: '50%',
                                    background: 'rgba(0, 230, 118, 0.1)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    color: 'var(--s-neon)'
                                }}>
                                    <User size={18} />
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ fontWeight: 900, color: '#fff', fontSize: '1rem' }}>{selectedUser.nombre_vendedor}</div>
                                    <div style={{ fontSize: '0.65rem', color: 'var(--s-neon)', fontWeight: 700, textTransform: 'uppercase' }}>
                                        {selectedUser.rol === 'admin' ? 'Gerente' : 'Vendedor'}
                                    </div>
                                </div>
                                <button 
                                    type="button" 
                                    onClick={handleBack} 
                                    style={{
                                        background: 'none', border: 'none', color: '#ff5252', cursor: 'pointer',
                                        fontSize: '0.75rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '0.25rem'
                                    }}
                                >
                                    <ArrowLeft size={12} /> VOLVER
                                </button>
                            </div>

                            {/* Campo de Contraseña */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', textAlign: 'left' }}>
                                <label style={{ fontSize: '0.75rem', fontWeight: 800, color: 'var(--s-neon)', letterSpacing: '0.1em' }}>
                                    INGRESE SU CLAVE DE ACCESO
                                </label>
                                <div style={{ position: 'relative' }}>
                                    <Lock size={18} style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--s-neon)' }} />
                                    <input
                                        type={showPassword ? 'text' : 'password'}
                                        autoFocus
                                        required
                                        value={password}
                                        onChange={(e) => {
                                            setPassword(e.target.value)
                                            setError('')
                                        }}
                                        className="s-input"
                                        style={{ 
                                            paddingLeft: '3rem', 
                                            paddingRight: '3rem', 
                                            fontSize: '1.2rem', 
                                            height: '3.8rem', 
                                            fontWeight: 900,
                                            borderColor: error ? '#ff5252' : 'var(--s-neon)',
                                            color: '#fff',
                                            letterSpacing: showPassword ? 'normal' : '0.4em'
                                        }}
                                        placeholder="••••••"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(p => !p)}
                                        style={{
                                            position: 'absolute', right: '1.25rem', top: '50%', transform: 'translateY(-50%)',
                                            background: 'none', border: 'none', color: 'var(--s-neon)', cursor: 'pointer',
                                            display: 'flex', alignItems: 'center', padding: 0
                                        }}
                                    >
                                        {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                </div>
                                {error && (
                                    <span style={{ color: '#ff5252', fontSize: '0.75rem', fontWeight: 800, marginTop: '0.25rem', letterSpacing: '0.05em' }}>
                                        ⚠️ {error}
                                    </span>
                                )}
                            </div>

                            {/* Botón de envío */}
                            <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                type="submit"
                                className="s-btn s-btn-primary"
                                style={{
                                    width: '100%', height: '4rem', fontSize: '1.1rem', letterSpacing: '0.15em',
                                    fontWeight: 900
                                }}
                            >
                                INICIAR SESIÓN
                            </motion.button>
                        </motion.form>
                    )}
                </AnimatePresence>

                {/* Pie de página */}
                <div style={{ marginTop: '2.5rem', display: 'flex', justifyContent: 'center', gap: '2rem', fontSize: '0.7rem', color: 'var(--s-text-dim)' }}>
                    <span>BASE: GOOGLE SHEETS</span>
                    <span>|</span>
                    <span>v3.1 GS</span>
                </div>
            </div>
        </div>
    )
}

export default ProfileSelection
