import React from 'react'
import { ShoppingCart, BarChart3, Layers, HelpCircle, UserPlus, UserMinus, ClipboardList, X } from 'lucide-react'
import { useAuth } from '../context/AuthContext'

const NAV = [
    { id: 'pos', label: 'TERMINAL DE VENTA', Icon: ShoppingCart },
    { id: 'dashboard', label: 'ESTADÍSTICAS', Icon: BarChart3 },
    { id: 'inventory', label: 'INVENTARIO', Icon: Layers },
    { id: 'cuentas-por-cobrar', label: 'CUENTAS POR COBRAR', Icon: UserPlus },
    { id: 'cuentas-por-pagar', label: 'CUENTAS POR PAGAR', Icon: UserMinus },
    { id: 'reportes', label: 'REPORTES', Icon: ClipboardList },
]

const Sidebar = ({ activePage, setActivePage, isSidebarOpen, onCloseSidebar }) => {
    const { user } = useAuth()
    const isVendedor = user?.rol === 'vendedor'
    const filteredNav = isVendedor ? NAV.filter(n => n.id === 'pos') : NAV

    return (
        <>
            {/* Backdrop for mobile */}
            {isSidebarOpen && (
                <div 
                    className="s-sidebar-backdrop" 
                    onClick={onCloseSidebar}
                    style={{
                        position: 'fixed',
                        inset: 0,
                        background: 'rgba(0,0,0,0.5)',
                        backdropFilter: 'blur(4px)',
                        zIndex: 990,
                        display: 'none'
                    }}
                />
            )}

            <aside className={`s-sidebar no-print ${isSidebarOpen ? 'open' : ''}`}>
                <div className="s-panel" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.5rem', flex: 1, position: 'relative' }}>
                    
                    {/* Close button for mobile */}
                    <button 
                        className="s-sidebar-close-btn"
                        onClick={onCloseSidebar}
                        style={{
                            position: 'absolute',
                            top: '1rem',
                            right: '1rem',
                            background: 'transparent',
                            border: 'none',
                            color: 'var(--s-neon)',
                            cursor: 'pointer',
                            display: 'none'
                        }}
                    >
                        <X size={20} />
                    </button>

                    <span className="s-section-label">Menú Principal</span>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem' }}>
                        {filteredNav.map(({ id, label, Icon }) => (
                            <button
                                key={id}
                                className={`s-nav-btn ${activePage === id ? 'active' : ''}`}
                                onClick={() => setActivePage(id)}
                            >
                                <Icon size={18} style={{ color: activePage === id ? '#000' : 'var(--s-neon)' }} />
                                {label}
                            </button>
                        ))}
                    </div>

                    <div style={{ marginTop: 'auto', paddingTop: '1rem' }}>
                        <button
                            className="s-nav-btn"
                            onClick={() => window.dispatchEvent(new CustomEvent('toggle-help'))}
                        >
                            <HelpCircle size={18} style={{ color: 'var(--s-neon)' }} />
                            AYUDA (F1)
                        </button>
                    </div>
                </div>
            </aside>
        </>
    )
}

export default Sidebar