import React from 'react'
import { X, User, Check } from 'lucide-react'
import { motion } from 'framer-motion'
import { useAuth } from '../context/AuthContext'
import { useToast } from '../context/ToastContext'
import { gsService } from '../lib/googleSheetsService'

const DEFAULT_USERS = [
    { id: 'admin', nombre_vendedor: 'ADMINISTRADOR', rol: 'admin' },
    { id: 'pastor_mejia', nombre_vendedor: 'PASTOR MEJIA', rol: 'admin' },
    { id: 'vendedor_1', nombre_vendedor: 'VENDEDOR 1', rol: 'vendedor' },
    { id: 'vendedor_2', nombre_vendedor: 'VENDEDOR 2', rol: 'vendedor' },
    { id: 'soporte', nombre_vendedor: 'SOPORTE TÉCNICO', rol: 'admin' }
]

const UserSelectionModal = ({ onClose }) => {
    const { user: currentUser, login } = useAuth()
    const { showToast } = useToast()

    const dbUsers = gsService.getTable('Usuarios') || []
    const users = dbUsers.length > 0 ? dbUsers.map((u, index) => ({
        id: String(u.id || u.nombre || index),
        nombre_vendedor: String(u.nombre || '').toUpperCase(),
        rol: String(u.rol || 'vendedor').toLowerCase() === 'administrador' ? 'admin' : 'vendedor'
    })) : DEFAULT_USERS

    const handleSelect = (user) => {
        login(user)
        showToast(`SESIÓN INICIADA: ${user.nombre_vendedor}`, 'success')
        onClose()
    }

    return (
        <div className="s-overlay" style={{ zIndex: 10000 }}>
            <motion.div
                className="s-overlay__backdrop"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={onClose}
            />

            <motion.div
                initial={{ scale: 0.95, opacity: 0, y: 20 }}
                animate={{ scale: 1, opacity: 1, y: 0 }}
                exit={{ scale: 0.95, opacity: 0, y: 20 }}
                className="s-modal s-modal--crystal"
                style={{ width: '28rem' }}
            >
                <div className="s-modal__header">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <User size={22} style={{ color: 'var(--s-neon)' }} />
                        <h3 style={{ fontSize: '1.2rem', fontWeight: 1000, color: '#fff', margin: 0 }}>
                            CAMBIAR DE USUARIO
                        </h3>
                    </div>
                    <button onClick={onClose} className="s-btn s-btn-secondary s-btn-icon">
                        <X size={20} />
                    </button>
                </div>

                <div className="s-modal__body" style={{ gap: '1rem', padding: '1.5rem 0' }}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                        {users.map((usr) => {
                            const isActive = currentUser?.id === usr.id
                            return (
                                <motion.div
                                    key={usr.id}
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                    onClick={() => handleSelect(usr)}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'space-between',
                                        padding: '1rem 1.5rem',
                                        background: isActive ? 'rgba(0, 230, 118, 0.08)' : 'rgba(255, 255, 255, 0.02)',
                                        border: `1px solid ${isActive ? 'var(--s-neon)' : 'var(--s-glass-border)'}`,
                                        borderRadius: '10px',
                                        cursor: 'pointer',
                                        transition: 'border-color 0.2s, background-color 0.2s'
                                    }}
                                >
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                        <div style={{
                                            width: '2.5rem',
                                            height: '2.5rem',
                                            borderRadius: '50%',
                                            background: isActive ? 'rgba(0, 230, 118, 0.1)' : 'rgba(255, 255, 255, 0.05)',
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            color: isActive ? 'var(--s-neon)' : 'var(--s-text-dim)'
                                        }}>
                                            <User size={18} />
                                        </div>
                                        <div style={{ textAlign: 'left' }}>
                                            <div style={{ 
                                                fontSize: '0.95rem', 
                                                fontWeight: 800, 
                                                color: isActive ? '#fff' : 'var(--s-text-dim)' 
                                            }}>
                                                {usr.nombre_vendedor}
                                            </div>
                                            <div style={{ 
                                                fontSize: '0.7rem', 
                                                fontWeight: 700, 
                                                color: isActive ? 'var(--s-neon)' : '#888',
                                                textTransform: 'uppercase',
                                                marginTop: '0.1rem'
                                            }}>
                                                {usr.rol === 'admin' ? 'Gerente' : 'Vendedor'}
                                            </div>
                                        </div>
                                    </div>

                                    {isActive && (
                                        <div style={{
                                            width: '1.5rem',
                                            height: '1.5rem',
                                            borderRadius: '50%',
                                            background: 'var(--s-neon)',
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            color: '#000'
                                        }}>
                                            <Check size={12} strokeWidth={3} />
                                        </div>
                                    )}
                                </motion.div>
                            )
                        })}
                    </div>
                </div>
            </motion.div>
        </div>
    )
}

export default UserSelectionModal
