import React, { useState, useEffect } from 'react'
import { Bell, Landmark, Unlock, Lock, LogOut, ShieldCheck, User, DollarSign, Power, Menu } from 'lucide-react'
import { createPortal } from 'react-dom'
import { useCaja } from '../context/CajaContext'
import { useAuth } from '../context/AuthContext'
import { useToast } from '../context/ToastContext'
import CajaModal from './CajaModal'
import UserSelectionModal from './UserSelectionModal'
import ExitConfirmationModal from './ExitConfirmationModal'
import dayjs from 'dayjs'

const Header = ({ isOnline, onToggleSidebar }) => {
    const [time, setTime] = useState(new Date())
    const [showCajaModal, setShowCajaModal] = useState(false)
    const [showUserModal, setShowUserModal] = useState(false)
    const [showExitModal, setShowExitModal] = useState(false)
    const [cajaModalType, setCajaModalType] = useState('abrir')
    const { sesionActiva, setSesionActiva, loadingCaja, tasaBCV, isCajaAbierta } = useCaja()
    const { user, logout } = useAuth()
    const { showToast } = useToast()

    useEffect(() => {
        const t = setInterval(() => setTime(new Date()), 1000)
        return () => clearInterval(t)
    }, [])

    const handleCajaClick = () => {
        if (sesionActiva && sesionActiva.abierto_por) {
            const creador = String(sesionActiva.abierto_por).toLowerCase().trim()
            const nombreUsuario = String(user?.nombre_vendedor || '').toLowerCase().trim()
            if (creador !== nombreUsuario) {
                showToast(`CAJA ABIERTA POR ${sesionActiva.abierto_por.toUpperCase()}. INICIE SESIÓN CON ESE USUARIO PARA CERRARLA.`, 'warning')
                return
            }
        }
        setCajaModalType(sesionActiva ? 'cerrar' : 'abrir')
        setShowCajaModal(true)
    }

    const hhmm = time.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true })
    const date = time.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })

    const displayName = user?.nombre_vendedor || 'Usuario'
    const displayRole = user?.rol === 'admin' ? 'Gerente de Tienda' : 'Asistente de Ventas'

    return (
        <header className="s-header">
            {/* Mobile Hamburger & Logo */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                <button
                    className="s-hamburger-btn"
                    onClick={onToggleSidebar}
                    style={{
                        background: 'transparent',
                        border: 'none',
                        color: 'var(--s-neon)',
                        cursor: 'pointer',
                        padding: '0.5rem',
                        alignItems: 'center',
                        justifyContent: 'center',
                    }}
                >
                    <Menu size={22} />
                </button>
                <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                    <h1 style={{ fontSize: '1.2rem', fontWeight: 900, color: '#fff', letterSpacing: '-0.02em' }}>
                        GLOBAL POS <span style={{ color: 'var(--s-neon)', fontStyle: 'italic' }}>DM</span>
                    </h1>
                </div>
            </div>

            {/* Clock Overlay */}
            <div className="s-panel" style={{ padding: '0.4rem 1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center', background: 'rgba(255,255,255,0.02)', border: 'none' }}>
                <span style={{ fontSize: '1.4rem', fontWeight: 900, color: '#fff', lineHeight: 1 }}>{hhmm}</span>
                <span style={{ fontSize: '0.65rem', fontWeight: 700, color: '#fff', textTransform: 'uppercase', marginTop: '0.2rem' }}>{date}</span>
            </div>

            {/* Status & User */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', fontSize: '0.75rem', fontWeight: 900, background: 'rgba(255,255,255,0.03)', padding: '0.4rem 0.8rem', borderRadius: '6px', border: '1px solid var(--s-glass-border)' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: isOnline ? 'var(--s-neon)' : '#ff5252', boxShadow: isOnline ? '0 0 10px var(--s-neon)' : 'none' }} />
                    <span style={{ color: isOnline ? '#fff' : '#ff5252' }}>{isOnline ? 'ONLINE' : 'OFFLINE'}</span>
                </div>


                {/* Caja Status Button */}
                {!loadingCaja && (() => {
                    const creador = String(sesionActiva?.abierto_por || '').toLowerCase().trim();
                    const nombreUsuario = String(user?.nombre_vendedor || '').toLowerCase().trim();
                    const isOwner = !sesionActiva || !sesionActiva.abierto_por || creador === nombreUsuario;
                    const canClick = user?.rol === 'admin';
                    const buttonTitle = !sesionActiva 
                        ? "Abrir Caja" 
                        : isOwner 
                            ? "Cerrar Caja" 
                            : `Caja abierta por ${sesionActiva.abierto_por}. Inicie sesión con ese usuario para cerrarla.`;
                    
                    return (
                        <button
                            onClick={canClick ? handleCajaClick : undefined}
                            title={buttonTitle}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '0.6rem',
                                padding: '0.4rem 1rem', borderRadius: '8px', 
                                cursor: canClick ? 'pointer' : 'default',
                                background: sesionActiva 
                                    ? (isOwner ? 'rgba(0,230,118,0.08)' : 'rgba(255,152,0,0.08)') 
                                    : 'rgba(255,82,82,0.08)',
                                border: `1px solid ${sesionActiva 
                                    ? (isOwner ? 'rgba(0,230,118,0.3)' : 'rgba(255,152,0,0.3)') 
                                    : 'rgba(255,82,82,0.3)'}`,
                                color: sesionActiva 
                                    ? (isOwner ? 'var(--s-neon)' : '#ff9800') 
                                    : '#ff5252',
                                fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.08em', transition: 'all 0.2s',
                                opacity: canClick ? (isOwner ? 1 : 0.7) : 0.5
                            }}
                        >
                            {sesionActiva ? <Unlock size={14} /> : <Lock size={14} />}
                            <div style={{ textAlign: 'left' }}>
                                <div>{sesionActiva ? (isOwner ? 'CAJA ABIERTA' : 'CAJA AJENA') : 'CAJA CERRADA'}</div>
                                 {sesionActiva && (() => {
                                     const rawName = sesionActiva.abierto_por || 'ADMINISTRADOR';
                                     const formattedName = rawName.toLowerCase().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
                                     return (
                                         <div style={{ fontSize: '0.55rem', fontWeight: 700, opacity: 0.7 }}>
                                             Por: {formattedName}
                                         </div>
                                     );
                                 })()}
                            </div>
                            <Landmark size={14} style={{ opacity: 0.6 }} />
                        </button>
                    );
                })()}

                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', paddingLeft: '1.5rem', borderLeft: '1px solid var(--s-glass-border)' }}>
                    <div style={{ textAlign: 'right' }}>
                        <div style={{ fontSize: '0.85rem', fontWeight: 800, color: '#fff' }}>{displayName}</div>
                        <div style={{ fontSize: '0.65rem', fontWeight: 700, color: 'var(--s-neon)', textTransform: 'uppercase' }}>{user?.rol || 'SISTEMA'}</div>
                    </div>
                    <button
                        onClick={() => setShowUserModal(true)}
                        title="Cambiar Usuario / Vendedor"
                        style={{
                            background: 'rgba(255,255,255,0.05)', border: '1px solid var(--s-glass-border)',
                            color: '#fff', width: '2.2rem', height: '2.2rem', borderRadius: '8px',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            cursor: 'pointer', transition: 'all 0.2s',
                            marginLeft: '0.5rem'
                        }}
                        onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--s-neon)'}
                        onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--s-glass-border)'}
                    >
                        <User size={16} />
                    </button>

                    <button
                        onClick={() => setShowExitModal(true)}
                        title="Salir del Sistema"
                        style={{
                            background: 'rgba(255,82,82,0.08)', border: '1px solid rgba(255,82,82,0.3)',
                            color: '#ff5252', width: '2.2rem', height: '2.2rem', borderRadius: '8px',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            cursor: 'pointer', transition: 'all 0.2s',
                            marginLeft: '0.5rem'
                        }}
                        onMouseEnter={e => {
                            e.currentTarget.style.background = 'rgba(255,82,82,0.15)'
                            e.currentTarget.style.borderColor = '#ff5252'
                        }}
                        onMouseLeave={e => {
                            e.currentTarget.style.background = 'rgba(255,82,82,0.08)'
                            e.currentTarget.style.borderColor = 'rgba(255,82,82,0.3)'
                        }}
                    >
                        <Power size={16} />
                    </button>
                </div>
            </div>

            {showCajaModal && createPortal(
                <CajaModal
                    type={cajaModalType}
                    onClose={() => setShowCajaModal(false)}
                    onSessionUpdate={setSesionActiva}
                    sesionActiva={sesionActiva}
                />,
                document.body
            )}

            {showUserModal && createPortal(
                <UserSelectionModal
                    onClose={() => setShowUserModal(false)}
                />,
                document.body
            )}

            {showExitModal && createPortal(
                <ExitConfirmationModal
                    onClose={() => setShowExitModal(false)}
                />,
                document.body
            )}
        </header>
    )
}

export default Header
