import React, { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { DatabaseZap } from 'lucide-react'

const SplashScreen = () => {
    const [progress, setProgress] = useState(0)

    useEffect(() => {
        const interval = setInterval(() => {
            setProgress((prev) => {
                if (prev >= 100) {
                    clearInterval(interval)
                    return 100
                }
                return prev + 2.5 // 100% en 4000ms (40 steps * 100ms)
            })
        }, 100)
        return () => clearInterval(interval)
    }, [])

    return (
        <div style={{
            height: '100vh',
            width: '100vw',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            background: 'radial-gradient(circle at center, #0a1f14 0%, #000 100%)',
            position: 'fixed',
            top: 0,
            left: 0,
            zIndex: 100000,
            color: '#fff'
        }}>
            <div style={{ textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2rem' }}>
                {/* Logo animado con efecto neón */}
                <motion.div
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: [0.8, 1.05, 1], opacity: 1 }}
                    transition={{ duration: 1.5, ease: 'easeOut' }}
                    style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}
                >
                    <h1 style={{
                        fontSize: '3.5rem',
                        fontWeight: 1000,
                        letterSpacing: '0.15em',
                        color: '#fff',
                        margin: 0,
                        textShadow: '0 0 15px rgba(0, 230, 118, 0.4), 0 0 30px rgba(0, 230, 118, 0.2)'
                    }}>
                        GLOBALPOS <span style={{ color: 'var(--s-neon)', fontStyle: 'italic' }}>DM</span>
                    </h1>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginTop: '0.5rem' }}>
                        <DatabaseZap size={16} style={{ color: 'var(--s-neon)' }} />
                        <span style={{ fontSize: '0.75rem', fontWeight: 900, color: 'var(--s-neon)', letterSpacing: '0.2em', textTransform: 'uppercase' }}>
                            SISTEMA DE PUNTO DE VENTA
                        </span>
                    </div>
                </motion.div>

                {/* Barra de progreso */}
                <div style={{ width: '200px', height: '4px', background: 'rgba(255,255,255,0.05)', borderRadius: '10px', overflow: 'hidden', border: '1px solid rgba(255,255,255,0.02)', position: 'relative' }}>
                    <motion.div
                        style={{
                            height: '100%',
                            background: 'var(--s-neon)',
                            width: `${progress}%`,
                            boxShadow: '0 0 10px var(--s-neon)'
                        }}
                    />
                </div>

                {/* Pie de página */}
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.6 }}
                    transition={{ delay: 1 }}
                    style={{ fontSize: '0.65rem', color: 'var(--s-text-dim)', letterSpacing: '0.1em', marginTop: '2rem' }}
                >
                    CARGANDO MÓDULOS DE CONEXIÓN...
                </motion.div>
            </div>
        </div>
    )
}

export default SplashScreen
