import React from 'react'
import { X, AlertTriangle, Power } from 'lucide-react'
import { motion } from 'framer-motion'
import { useCaja } from '../context/CajaContext'
import { useAuth } from '../context/AuthContext'
import { useToast } from '../context/ToastContext'

const ExitConfirmationModal = ({ onClose }) => {
    const { isCajaAbierta } = useCaja()
    const { logout } = useAuth()
    const { showToast } = useToast()

    const handleConfirmExit = () => {
        if (isCajaAbierta) {
            showToast('Caja Abierta, debe cerrarla primero', 'error')
            return
        }

        // Si la caja está cerrada, proceder a cerrar el sistema
        logout()
        showToast('CERRANDO EL SISTEMA...', 'info')
        
        // Intentar cerrar la pestaña
        setTimeout(() => {
            window.close()
            // Fallback si el navegador bloquea window.close()
            window.location.href = 'about:blank'
        }, 1000)
    }

    return (
        <div className="s-overlay" style={{ zIndex: 10000 }}>
            <motion.div
                className="s-overlay__backdrop"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={onClose}
            />

            <motion.div
                initial={{ scale: 0.95, opacity: 0, y: 20 }}
                animate={{ scale: 1, opacity: 1, y: 0 }}
                exit={{ scale: 0.95, opacity: 0, y: 20 }}
                className="s-modal s-modal--crystal"
                style={{ width: '26rem', borderColor: 'rgba(255, 82, 82, 0.2)' }}
            >
                <div className="s-modal__header">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Power size={22} style={{ color: '#ff5252' }} />
                        <h3 style={{ fontSize: '1.2rem', fontWeight: 1000, color: '#fff', margin: 0 }}>
                            CERRAR EL SISTEMA
                        </h3>
                    </div>
                    <button onClick={onClose} className="s-btn s-btn-secondary s-btn-icon">
                        <X size={20} />
                    </button>
                </div>

                <div className="s-modal__body" style={{ gap: '1.5rem', padding: '1.5rem 1.75rem', textAlign: 'center', display: 'flex', flexDirection: 'column' }}>
                    <div style={{
                        width: '3.5rem',
                        height: '3.5rem',
                        borderRadius: '50%',
                        background: 'rgba(255, 82, 82, 0.1)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#ff5252',
                        margin: '0 auto 0.5rem auto'
                    }}>
                        <AlertTriangle size={28} />
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        <p style={{ fontSize: '1.1rem', fontWeight: 800, color: '#fff', margin: 0 }}>
                            ¿Está seguro de que desea Cerrar el Sistema?
                        </p>
                        <p style={{ fontSize: '0.8rem', color: 'var(--s-text-dim)', margin: 0 }}>
                            Se cerrará la sesión actual y se intentará cerrar la ventana del navegador.
                        </p>
                    </div>

                    {isCajaAbierta && (
                        <div style={{ 
                            background: 'rgba(255, 82, 82, 0.08)', 
                            border: '1px solid rgba(255, 82, 82, 0.2)',
                            borderRadius: '8px',
                            padding: '0.75rem',
                            color: '#ff5252',
                            fontSize: '0.75rem',
                            fontWeight: 800
                        }}>
                            ⚠️ CAJA ABIERTA: Debe realizar el arqueo y cierre de caja antes de salir.
                        </div>
                    )}

                    <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                        <button
                            onClick={onClose}
                            className="s-btn s-btn-secondary"
                            style={{ flex: 1, height: '3rem', fontSize: '0.9rem', fontWeight: 900 }}
                        >
                            NO, REGRESAR
                        </button>
                        <button
                            onClick={handleConfirmExit}
                            className="s-btn"
                            style={{ 
                                flex: 1, 
                                height: '3rem', 
                                fontSize: '0.9rem', 
                                fontWeight: 900,
                                background: '#ff5252',
                                borderColor: '#ff5252',
                                color: '#fff'
                            }}
                        >
                            SÍ, CERRAR
                        </button>
                    </div>
                </div>
            </motion.div>
        </div>
    )
}

export default ExitConfirmationModal
